#include <stdio.h>
#include <stdlib.h>

// Node definition for linked list with child pointers
typedef struct ListNode {
    int val;
    struct ListNode* next;
    struct ListNode* child;
} ListNode;

// Function to convert an array to a linked list
ListNode* convertArrToLinkedList(int* arr, int size) {
    ListNode* dummyNode = (ListNode*)malloc(sizeof(ListNode));
    dummyNode->val = -1;
    dummyNode->next = NULL;
    dummyNode->child = NULL;
    ListNode* temp = dummyNode;

    for (int i = 0; i < size; i++) {
        temp->child = (ListNode*)malloc(sizeof(ListNode));
        temp->child->val = arr[i];
        temp->child->next = NULL;
        temp->child->child = NULL;
        temp = temp->child;
    }
    return dummyNode->child;
}

// Function to flatten a linked list with child pointers 
ListNode* flattenLinkedList(ListNode* head) {
    int* arr = NULL;
    int size = 0;

    // Traverse through the linked list
    while (head != NULL) {
        ListNode* t2 = head;
        while (t2 != NULL) {
            arr = (int*)realloc(arr, (size + 1) * sizeof(int));
            arr[size] = t2->val;
            size++;
            t2 = t2->child;
        }
        head = head->next;
    }

    // Sort the array containing node values
    for (int i = 0; i < size - 1; i++) {
        for (int j = i + 1; j < size; j++) {
            if (arr[i] > arr[j]) {
                int temp = arr[i];
                arr[i] = arr[j];
                arr[j] = temp;
            }
        }
    }

    // Convert the sorted array back to a linked list
    return convertArrToLinkedList(arr, size);
}

// Function to print the linked list
void printLinkedList(ListNode* head) {
    while (head != NULL) {
        printf("%d ", head->val);
        head = head->child;
    }
    printf("\n");
}

